const express = require('express');
const session = require('express-session');
const { Issuer, generators } = require('openid-client');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');

const app = express();

app.use(session({
  secret: 'change-this-to-secure-random-string',
  resave: false,
  saveUninitialized: false,
  cookie: { secure: true, httpOnly: true, sameSite: 'lax' }
}));

let client;
const jwksClientInstance = jwksClient({
  jwksUri: 'https://your-oidc-provider.com/.well-known/jwks.json',
  cache: true,
  cacheMaxAge: 86400000
});

async function initializeOIDC() {
  const issuer = await Issuer.discover('https://your-oidc-provider.com');
  client = new issuer.Client({
    client_id: 'your-client-id',
    client_secret: 'your-client-secret',
    redirect_uris: ['http://localhost:3000/callback'],
    response_types: ['code']
  });
}

function getKey(header, callback) {
  jwksClientInstance.getSigningKey(header.kid, (err, key) => {
    if (err) return callback(err);
    callback(null, key.getPublicKey());
  });
}

function verifyToken(token) {
  return new Promise((resolve, reject) => {
    jwt.verify(token, getKey, {
      algorithms: ['RS256'],
      issuer: 'https://your-oidc-provider.com',
      audience: 'your-client-id'
    }, (err, decoded) => {
      if (err) return reject(err);
      resolve(decoded);
    });
  });
}

app.get('/login', (req, res) => {
  const nonce = generators.nonce();
  const state = generators.state();
  
  req.session.nonce = nonce;
  req.session.state = state;
  
  const authUrl = client.authorizationUrl({
    scope: 'openid profile email',
    state: state,
    nonce: nonce
  });
  
  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  try {
    const params = client.callbackParams(req);
    const tokenSet = await client.callback(
      'http://localhost:3000/callback',
      params,
      { nonce: req.session.nonce, state: req.session.state }
    );
    
    const claims = await verifyToken(tokenSet.id_token);
    
    req.session.user = {
      id: claims.sub,
      email: claims.email,
      name: claims.name
    };
    
    res.redirect('/dashboard');
  } catch (err) {
    console.error('Authentication error:', err);
    res.status(401).send('Authentication failed');
  }
});

app.get('/dashboard', (req, res) => {
  if (!req.session.user) {
    return res.redirect('/login');
  }
  res.send(`Welcome ${req.session.user.name}`);
});

initializeOIDC().then(() => {
  app.listen(3000, () => console.log('Server running on port 3000'));
});